class VersionModel {  bool? success;  String? message;  VersionData? data;  VersionModel({this.success, this.message, this.data});  VersionModel.fromJson(Map<String, dynamic> json) {    success = json['success'];    message = json['message'];    data = json['data'] != null ? new VersionData.fromJson(json['data']) : null;  }  Map<String, dynamic> toJson() {    final Map<String, dynamic> data = new Map<String, dynamic>();    data['success'] = this.success;    data['message'] = this.message;    if (this.data != null) {      data['data'] = this.data!.toJson();    }    return data;  }}class VersionData {  int? id;  dynamic? androidVersion;  dynamic? iosVersion;  dynamic? playstoreLink;  dynamic? appstoreLink;  dynamic? androidOtherLink;  dynamic? iosOtherLink;  dynamic? releaseNote;  String? createdAt;  String? updatedAt;  VersionData(      {this.id,        this.androidVersion,        this.iosVersion,        this.playstoreLink,        this.appstoreLink,        this.androidOtherLink,        this.iosOtherLink,        this.releaseNote,        this.createdAt,        this.updatedAt});  VersionData.fromJson(Map<String, dynamic> json) {    id = json['id'];    androidVersion = json['android_version'];    iosVersion = json['ios_version'];    playstoreLink = json['playstore_link'];    appstoreLink = json['appstore_link'];    androidOtherLink = json['android_other_link'];    iosOtherLink = json['ios_other_link'];    releaseNote = json['release_note'];    createdAt = json['created_at'];    updatedAt = json['updated_at'];  }  Map<String, dynamic> toJson() {    final Map<String, dynamic> data = new Map<String, dynamic>();    data['id'] = this.id;    data['android_version'] = this.androidVersion;    data['ios_version'] = this.iosVersion;    data['playstore_link'] = this.playstoreLink;    data['appstore_link'] = this.appstoreLink;    data['android_other_link'] = this.androidOtherLink;    data['ios_other_link'] = this.iosOtherLink;    data['release_note'] = this.releaseNote;    data['created_at'] = this.createdAt;    data['updated_at'] = this.updatedAt;    return data;  }}